namespace sv_acece511e2ad4c9fba8f0d740e48dad7.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@using sv_acece511e2ad4c9fba8f0d740e48dad7.Services
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

<div class="row">
    @* Left sidebar — filters *@
    <div class="col-lg-3 mb-4">
        <CatalogFilters Categories="categories" OnFiltersApplied="HandleFiltersApplied" />
    </div>

    @* Main content area *@
    <div class="col-lg-9">
        @if (errorMessage is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @errorMessage
                <button class="btn btn-sm btn-outline-danger ms-3" @onclick="RetryLoad">Retry</button>
            </div>
        }
        else if (isLoading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
                <span class="ms-3 text-muted">Loading products…</span>
            </div>
        }
        else if (result is not null && result.Items.Count > 0)
        {
            <CatalogToolbar SortBy="@sortBy"
                            TotalCount="result.TotalCount"
                            Page="result.Page"
                            PageSize="pageSize"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="result.Items"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />

            @if (totalPages > 1)
            {
                <div class="mt-4">
                    <CatalogPagination Page="currentPage"
                                       TotalPages="totalPages"
                                       OnPageChanged="HandlePageChanged" />
                </div>
            }
        }
        else
        {
            <div class="text-center py-5 text-muted">
                <h4>No products found</h4>
                <p>Try adjusting your filters to see more results.</p>
            </div>
        }
    </div>
</div>

@code {
    private List<string>? categories;
    private PagedResult<Product>? result;
    private ProductFilter currentFilter = new(null, null, null, false);
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int pageSize = 9;
    private bool isLoading = true;
    private string? errorMessage;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private int totalPages => result is null || result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)result.TotalCount / pageSize);

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var categoriesTask = categories is null
                ? ProductService.GetCategoriesAsync()
                : Task.FromResult(categories);

            var searchTask = ProductService.SearchAsync(currentFilter, sortBy, currentPage, pageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            categories = await categoriesTask;
            result = await searchTask;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleFiltersApplied(ProductFilter filter)
    {
        currentFilter = filter;
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandleSortChanged(string newSort)
    {
        sortBy = newSort;
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await LoadDataAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for add-to-cart logic
        return Task.CompletedTask;
    }

    private async Task RetryLoad()
    {
        await LoadDataAsync();
    }
}

